import{_ as t}from"./plugin-vue_export-helper.21dcd24c.js";import{r as e,o as c,c as s,a,w as i,e as r}from"./app.b6fba8d5.js";const l={},d=r('<h1 id="miniscaled" tabindex="-1"><a class="header-anchor" href="#miniscaled" aria-hidden="true">#</a> MiniScaled</h1><p>MiniScaled is a Fabric mod that provides easy-usable scale boxes using Immersive Portals functionality. You can enter the scale box seamlessly without loading screen. <a href="https://github.com/qouteall/MiniScaledMod" target="_blank" rel="noopener noreferrer">GitHub</a></p><p><img src="https://i.loli.net/2021/09/30/J9bBF82tRu5yIkW.png" alt="miniscaled1.png"></p><p><a href="#download">Download Below</a> <a href="https://www.curseforge.com/minecraft/mc-mods/miniscaled" target="_blank" rel="noopener noreferrer">Or Download from CurseForge</a></p><h2 id="how-to-use" tabindex="-1"><a class="header-anchor" href="#how-to-use" aria-hidden="true">#</a> How to Use</h2><p>(This describes the latest version of MiniScaled)</p><p>In survival mode, you can build a block frame using stained glass: (The frame must be either 4x4x4 or 8x8x8 or 16x16x16 or 32x32x32.)</p><p><img src="https://s2.loli.net/2022/03/20/Rg3WscPd5yQYV9T.png" alt="create entrance.png"></p><p>Then use a netherite ingot to right-click it, you will get a <strong>scale box entrance</strong> item. You can place the scale box entrance.</p><p>The actual scale box is in another dimension (<code>mini_scaled:void</code>). The scale boxes are discriminated by its color, size and owner. (You can enter a scale box owned by other players.)</p><p>The scale box entrance item is just an entrance and does not hold the actual scale box. If you lose the entrance item, you can create another entrance with the same size and color. If two entrances of one scale box are placed, one entrance will break.</p><p>In creative mode you can get scale box entrances in the Miscellaneous tab</p><p><img src="https://i.loli.net/2021/09/30/bSmanXtOcPHl1rQ.png" alt="scale box misc tab.png"></p><p>You can put a scale box inside itself and create a fractal.</p><p>When you are standing on the top of a scale box, crouch(press shift) to descend.</p><p>When crouching, you can break or place blocks in the scale box when you are not in the scale box.</p><h3 id="expand-and-shrink-the-scale-box" tabindex="-1"><a class="header-anchor" href="#expand-and-shrink-the-scale-box" aria-hidden="true">#</a> Expand and Shrink the Scale Box</h3><p>When holding a scale box entrance item, right-clicking a scale box can expand the scale box. The scale box can only be expanded from up, south and east faces. The scale box item&#39;s color, scale and owner should match. Using bare hand to right-click a scale box can shrink it.</p><h2 id="download" tabindex="-1"><a class="header-anchor" href="#download" aria-hidden="true">#</a> Download</h2>',19);function h(p,u){const n=e("ModDownload"),o=e("ClientOnly");return c(),s("div",null,[d,a(o,null,{default:i(()=>[a(n,{github_repo:"qouteall/MiniScaledMod",locale_text:{download:"Download",preRelease:"Pre-Release",publishTime:"Publish time"}})]),_:1})])}var x=t(l,[["render",h],["__file","MiniScaled.html.vue"]]);export{x as default};
